-- Langar Bar V5.4.0 Smart Drink Knowledge Base
create extension if not exists pg_trgm;
create table if not exists public.langar_knowledge_entries (id uuid primary key default gen_random_uuid(),slug text unique not null,category text not null,name_en text not null,name_hr text not null,summary_en text not null,summary_hr text not null,details_en text,details_hr text,recipe jsonb not null default '{}'::jsonb,keywords text[] not null default '{}',aliases text[] not null default '{}',allergen_note text,active boolean not null default true,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
alter table public.barista_questions add column if not exists answer_source text default 'human';
alter table public.barista_questions add column if not exists matched_knowledge_id uuid references public.langar_knowledge_entries(id);
alter table public.barista_questions add column if not exists answered_at timestamptz;
create index if not exists langar_knowledge_name_en_trgm on public.langar_knowledge_entries using gin (name_en gin_trgm_ops);
create index if not exists langar_knowledge_name_hr_trgm on public.langar_knowledge_entries using gin (name_hr gin_trgm_ops);
on conflict (slug) do update set category=excluded.category,name_en=excluded.name_en,name_hr=excluded.name_hr,summary_en=excluded.summary_en,summary_hr=excluded.summary_hr,details_en=excluded.details_en,details_hr=excluded.details_hr,recipe=excluded.recipe,keywords=excluded.keywords,aliases=excluded.aliases,allergen_note=excluded.allergen_note,active=excluded.active,updated_at=now();

create or replace function public.search_langar_knowledge_v540(p_question text,p_lang text default 'en') returns table(id uuid,slug text,category text,name_en text,name_hr text,summary_en text,summary_hr text,details_en text,details_hr text,recipe jsonb,keywords text[],aliases text[],allergen_note text,score numeric) language sql stable security definer set search_path=public as $$
with q as(select lower(trim(coalesce(p_question,''))) t), scored as(select k.*, greatest(similarity(lower(k.name_en),q.t),similarity(lower(k.name_hr),q.t),coalesce((select max(similarity(lower(x),q.t)) from unnest(k.aliases||k.keywords) x),0)) + case when q.t like '%'||lower(k.name_en)||'%' or q.t like '%'||lower(k.name_hr)||'%' then 1.2 else 0 end + coalesce((select count(*)*.18 from unnest(k.keywords||k.aliases) x where q.t like '%'||lower(x)||'%'),0) s from public.langar_knowledge_entries k,q where k.active) select id,slug,category,name_en,name_hr,summary_en,summary_hr,details_en,details_hr,recipe,keywords,aliases,allergen_note,round(s::numeric,3) from scored order by s desc limit 3;$$;
grant execute on function public.search_langar_knowledge_v540(text,text) to authenticated;

create or replace function public.smart_barista_ask_v540(p_question text,p_subject text default 'Drink question',p_lang text default 'en') returns jsonb language plpgsql security definer set search_path=public as $$declare u auth.users; k record; qid uuid; sensitive boolean; begin select * into u from auth.users where id=auth.uid(); if u.id is null then raise exception 'Authentication required'; end if; sensitive:=lower(p_question) ~ '(allerg|alerg|anaphyl|celiac|gluten|diabet|pregnan|medical|medicine|lijek|trudn|šećer|secer)'; select * into k from public.search_langar_knowledge_v540(p_question,p_lang) limit 1; if not sensitive and k.id is not null and k.score>=0.62 then insert into public.barista_questions(user_id,customer_email,subject,question,status,admin_reply,answer_source,matched_knowledge_id,answered_at,created_at) values(u.id,u.email,p_subject,p_question,'answered',case when p_lang='hr' then k.summary_hr||E'

'||coalesce(k.details_hr,'') else k.summary_en||E'

'||coalesce(k.details_en,'') end,'knowledge',k.id,now(),now()) returning id into qid; return jsonb_build_object('matched',true,'question_id',qid,'knowledge',to_jsonb(k)); else insert into public.barista_questions(user_id,customer_email,subject,question,status,answer_source,created_at) values(u.id,u.email,p_subject,p_question,'new','human',now()) returning id into qid; return jsonb_build_object('matched',false,'question_id',qid,'sensitive',sensitive); end if; end$$;
grant execute on function public.smart_barista_ask_v540(text,text,text) to authenticated;

create or replace function public.list_my_barista_questions_v540() returns table(id uuid,subject text,question text,status text,admin_reply text,answer_source text,created_at timestamptz,answered_at timestamptz) language sql stable security definer set search_path=public as $$select b.id,b.subject,b.question,b.status,b.admin_reply,b.answer_source,b.created_at,b.answered_at from public.barista_questions b where b.user_id=auth.uid() or lower(b.customer_email)=lower(coalesce(auth.jwt()->>'email','')) order by b.created_at desc limit 100$$;
grant execute on function public.list_my_barista_questions_v540() to authenticated;

create or replace function public.admin_list_knowledge_v540(p_search text default null,p_category text default null) returns setof public.langar_knowledge_entries language sql stable security definer set search_path=public as $$select * from public.langar_knowledge_entries k where (p_category is null or p_category='' or k.category=p_category) and (p_search is null or p_search='' or k.name_en ilike '%'||p_search||'%' or k.name_hr ilike '%'||p_search||'%' or exists(select 1 from unnest(k.keywords||k.aliases) x where x ilike '%'||p_search||'%')) order by k.category,k.name_en$$;
grant execute on function public.admin_list_knowledge_v540(text,text) to authenticated;
